// Calculate relevance score (0-100)
const item = $json;
const relevanceBreakdown = {
  ai_governance: 0,
  enterprise_strategy: 0,
  policy_community: 0,
  pca_impact: 0
};

// AI Governance keywords
if (/ai|artificial intelligence|regulation|responsible ai|liability|governance/i.test(item.title + item.summary)) {
  relevanceBreakdown.ai_governance = 25;
}

// Enterprise Strategy keywords
if (/platform|cloud|infrastructure|modernization|digital|roadmap/i.test(item.title + item.summary)) {
  relevanceBreakdown.enterprise_strategy = 20;
}

// Policy/Community keywords
if (/policy|regulation|parliament|senate|health|public|stakeholder/i.test(item.title + item.summary)) {
  relevanceBreakdown.policy_community = 22;
}

// PCA Impact keywords
if (/privacy|data protection|pipeda|gdpr|consent|security|breach/i.test(item.title + item.summary)) {
  relevanceBreakdown.pca_impact = 20;
}

const relevanceScore = Math.min(
  relevanceBreakdown.ai_governance + 
  relevanceBreakdown.enterprise_strategy + 
  relevanceBreakdown.policy_community + 
  relevanceBreakdown.pca_impact, 
  100
);

return { ...item, relevanceBreakdown, relevanceScore };

// Calculate novelty score (0-100) based on time since publication
const item = $json;
const publishedDate = new Date(item.published_date);
const now = new Date();
const hoursOld = (now - publishedDate) / (1000 * 60 * 60);

let noveltyScore;
if (hoursOld < 1) noveltyScore = 100;
else if (hoursOld < 6) noveltyScore = 80;
else if (hoursOld < 24) noveltyScore = 60;
else if (hoursOld < 48) noveltyScore = 30;
else noveltyScore = 10;

return { ...item, noveltyScore, hoursOld };

// Calculate quality score (0-100) based on source credibility
const item = $json;

const sourceCredibility = {
  'Reuters': 95,
  'AP': 95,
  'BBC': 90,
  'Guardian': 85,
  'CNN': 80,
  'Health Affairs': 90,
  'JAMA': 95,
  'NewsAPI': 70,
  'Twitter': 40,
  'Reddit': 30
};

const credibilityScore = sourceCredibility[item.source] || 60;
const editorialScore = item.source.includes('news') ? 80 : 50;
const qualityScore = Math.round((credibilityScore + editorialScore) / 2);

return { ...item, qualityScore, sourceCredibility: credibilityScore };

// Combine all scores: (0.4 × relevance) + (0.3 × novelty) + (0.3 × quality)
const item = $json;
const combinedScore = Math.round(
  (item.relevanceScore * 0.4) +
  (item.noveltyScore * 0.3) +
  (item.qualityScore * 0.3)
);

return { ...item, combinedScore };

// Route decision based on score
const item = $json;
let routing = {};

if (item.combinedScore >= 85) {
  routing = {
    alert: true,
    daily_brief: true,
    obsidian: true,
    airtable: true,
    teams: true,
    email: true,
    routing_decision: 'ALERT_AND_BRIEF'
  };
} else if (item.combinedScore >= 70) {
  routing = {
    alert: false,
    daily_brief: true,
    obsidian: true,
    airtable: true,
    teams: false,
    email: false,
    routing_decision: 'DAILY_BRIEF'
  };
} else if (item.combinedScore >= 50) {
  routing = {
    alert: false,
    daily_brief: false,
    obsidian: true,
    airtable: true,
    teams: false,
    email: false,
    routing_decision: 'ARCHIVE_ONLY'
  };
} else {
  routing = {
    alert: false,
    daily_brief: false,
    obsidian: false,
    airtable: true,
    teams: false,
    email: false,
    routing_decision: 'DISCARD'
  };
}

return { ...item, ...routing, scored_at: new Date().toISOString() };
